INSERT OR IGNORE INTO posts (id, bbsid, board_id, user_id, title, content, content_text, signature, posted_at, reply_count, source_file, wayback_ts) VALUES (2603, 221874, 13, 2384, '改变2003-新年快乐', '&nbsp;&nbsp;&nbsp;2003年终于过去了，今夜，特别找出黄舒骏的CD，听他那首改变1995，听他冷淡的声音像念经般一遍遍地说你走后没几天，邓丽君也和我们说再见，突然觉得鼻子酸酸，“世界不断地改变改变，我的心思却不愿意离开从前，时间不停地走远走远，我的记忆却停在&nbsp;却停在那2003年”。
<br>&nbsp;&nbsp;本来想写长一点，把这一年来积蓄在心里的一些块垒写出，包括对2003年一头一尾走掉的那两个我喜欢的公众人物，但突然间不想再写伤感的话，在新年到来的时候，向大家说，新年快乐，告别2003年！', '2003年终于过去了，今夜，特别找出黄舒骏的CD，听他那首改变1995，听他冷淡的声音像念经般一遍遍地说你走后没几天，邓丽君也和我们说再见，突然觉得鼻子酸酸，“世界不断地改变改变，我的心思却不愿意离开从前，时间不停地走远走远，我的记忆却停在 却停在那2003年”。

本来想写长一点，把这一年来积蓄在心里的一些块垒写出，包括对2003年一头一尾走掉的那两个我喜欢的公众人物，但突然间不想再写伤感的话，在新年到来的时候，向大家说，新年快乐，告别2003年！', NULL, '2004-01-01 00:31:00', 4, '20040211190352_bbsid_221874_board_13_078515d6ae.html', '20040211190352');
